SELECT protocol_name
FROM trial_protocols
WHERE status = 'active';

SELECT COUNT(*) AS active_protocol_count
FROM trial_protocols
WHERE status = 'active';

SELECT property_name
FROM vocabulary_properties
WHERE vocabulary_id = 1;

SELECT COUNT(property_id) AS property_count
FROM trial_protocol_properties
WHERE protocol_id = 1;

SELECT status, COUNT(*) as trial_count
FROM trial_protocols
GROUP BY status;
